B.Xv=new A.a3("A opini\xe3o \xe9 a mediadora entre o conhecimento e a ignor\xe2ncia.","Plat\xe3o")
B.Y1=new A.a3("Somos o que fazemos repetidamente. Excel\xeancia, ent\xe3o, n\xe3o \xe9 um ato, mas um h\xe1bito.","Arist\xf3teles")
B.XL=new A.a3("A raiz da educa\xe7\xe3o \xe9 amarga, mas seus frutos s\xe3o doces.","Arist\xf3teles")
B.XD=new A.a3("A felicidade \xe9 o significado e o prop\xf3sito da vida, o objetivo e o fim da exist\xeancia humana.","Arist\xf3teles")
B.Xk=new A.a3("O homem s\xe1bio n\xe3o diz tudo que pensa, mas sempre pensa tudo que diz.","Arist\xf3teles")
B.Xg=new A.a3("\xc9 durante os momentos mais dif\xedceis que encontramos a verdadeira medida do car\xe1ter.","Arist\xf3teles")
B.XK=new A.a3("A virtude \xe9 o meio-termo entre dois extremos, ambos viciosos.","Arist\xf3teles")
B.Yr=new A.a3("Devemos ser donos de nossas pr\xf3prias decis\xf5es, n\xe3o escravos das circunst\xe2ncias.","Arist\xf3teles")
B.X9=new A.a3("Voc\xea tem poder sobre sua mente, n\xe3o sobre os eventos externos. Perceba isso e encontrar\xe1 for\xe7a.","Marco Aur\xe9lio")
B.Yy=new A.a3("A melhor vingan\xe7a \xe9 n\xe3o ser como seu inimigo.","Marco Aur\xe9lio")
B.Yh=new A.a3("Perde seu tempo quem busca a aprova\xe7\xe3o dos outros.","Marco Aur\xe9lio")
B.WH=new A.a3("Quando voc\xea acorda de manh\xe3, pense no precioso privil\xe9gio de estar vivo: respirar, pensar, desfrutar e amar.","Marco Aur\xe9lio")
B.WX=new A.a3("A qualidade da sua vida \xe9 determinada pela qualidade dos seus pensamentos.","Marco Aur\xe9lio")
B.Yi=new A.a3("Nunca estime algo como lucrativo se te for\xe7ar a quebrar sua palavra ou perder seu autorrespeito.","Marco Aur\xe9lio")
B.WK=new A.a3("N\xe3o desperdice o resto de sua vida em pensamentos sobre outras pessoas.","Marco Aur\xe9lio")
B.Xs=new A.a3("O homem que faz tudo o que pode dentro das limita\xe7\xf5es que lhe foram impostas faz o suficiente.","Marco Aur\xe9lio")
B.XV=new A.a3("N\xe3o \xe9 o que acontece com voc\xea, mas como voc\xea reage ao que acontece com voc\xea que importa.","Epicteto")
B.XI=new A.a3("Fa\xe7a todo o poss\xedvel para n\xe3o depender de circunst\xe2ncias externas.","Epicteto")
B.XN=new A.a3("N\xe3o procure que as coisas que acontecem sejam como voc\xea quer. Deseje que as coisas que acontecem sejam como s\xe3o e voc\xea encontrar\xe1 tranquilidade.","Epicteto")
B.WC=new A.a3("Temos dois ouvidos e uma boca para que possamos ouvir duas vezes mais do que falamos.","Epicteto")
B.X8=new A.a3("A riqueza consiste n\xe3o em ter grandes posses, mas em ter poucas necessidades.","Epicteto")
B.Xz=new A.a3("Primeiro diga a si mesmo o que voc\xea ser\xe1; depois fa\xe7a o que tem a fazer.","Epicteto")
