B.Xu=new A.a3("Enquanto adiamos, a vida passa.","S\xeaneca")
B.Xd=new A.a3("\xc9 uma for\xe7a grande n\xe3o precisar de for\xe7a.","S\xeaneca")
B.XM=new A.a3("Retire-se para dentro de si mesmo tanto quanto puder com aqueles que v\xe3o fazer de voc\xea uma pessoa melhor.","S\xeaneca")
B.XB=new A.a3("A dificuldade que voc\xea supera hoje \xe9 a sabedoria que voc\xea carrega amanh\xe3.","S\xeaneca")
B.Y8=new A.a3("Cuide do corpo para que a mente possa habit\xe1-lo com prazer.","S\xeaneca")
B.Xf=new A.a3("Comece. N\xe3o h\xe1 nada que tanto retarde o progresso quanto esperar por ele.","S\xeaneca")
B.Xm=new A.a3("Viva com os seres humanos como se Deus te visse; fale com Deus como se os seres humanos te ouvissem.","S\xeaneca")
B.Xr=new A.a3("A mudan\xe7a \xe9 a \xfanica constante da vida.","Her\xe1clito")
B.Y6=new A.a3("N\xe3o \xe9 poss\xedvel pisar duas vezes no mesmo rio.","Her\xe1clito")
B.Yg=new A.a3("O car\xe1ter \xe9 o destino.","Her\xe1clito")
B.Y2=new A.a3("Muito aprender n\xe3o ensina a ter bom senso.","Her\xe1clito")
B.X7=new A.a3("A jornada de mil milhas come\xe7a com um \xfanico passo.","Lao Tzu")
B.Yw=new A.a3("Aquele que se conhece \xe9 s\xe1bio. Aquele que conquista os outros \xe9 forte. Aquele que conquista a si mesmo \xe9 poderoso.","Lao Tzu")
B.WJ=new A.a3("A natureza n\xe3o tem pressa, mas realiza tudo.","Lao Tzu")
B.Yf=new A.a3("Quando eu deixo de ser o que sou, torno-me o que poderia ser.","Lao Tzu")
B.Ya=new A.a3("Seja cuidadoso com seus pensamentos, eles se tornam suas palavras. Seja cuidadoso com suas palavras, elas se tornam suas a\xe7\xf5es.","Lao Tzu")
B.WW=new A.a3("Agir sem expectativa, realizar sem fazer alarde \u2014 isso \xe9 a virtude suprema.","Lao Tzu")
B.WN=new A.a3("N\xe3o importa qu\xe3o devagar voc\xea v\xe1, desde que n\xe3o pare.","Conf\xfacio")
