B.Y9=new A.a3("Aquele que aprende mas n\xe3o pensa est\xe1 perdido. Aquele que pensa mas n\xe3o aprende est\xe1 em grande perigo.","Conf\xfacio")
B.Y_=new A.a3("O que voc\xea pensa, voc\xea se torna. O que voc\xea sente, voc\xea atrai. O que voc\xea imagina, voc\xea cria.","Buda")
B.WR=new A.a3("A mente \xe9 tudo. O que voc\xea pensa, voc\xea se torna.","Buda")
